/// BTToggle atom barrel.
library;

export 'toggle.types.dart';
export 'toggle.widget.dart';

/// BTToggle types — Figma node 2855-1224.
library;

/// Visual style of the toggle.
enum BTToggleVariant {
  /// Default — filled background. Inactive: bg.subtle / Active: brand.primary.
  defaultVariant,

  /// Transparent with border when inactive; bg.subtle when active (no border).
  outline,
}

/// Padding scale of the toggle.
enum BTToggleSize {
  /// Default — 8 px on all sides, 14 px font.
  md,

  /// Small — 4 px on all sides, 12 px font.
  sm,
}

/// BTToggle — pressable pill toggle atom.
/// Figma source: node 2855-1224 (light) · 4735-14291 (dark).
///
/// Caller controls [pressed] state. Component fires [onChanged](!pressed) on tap.
/// Pass [onChanged] as `null` to disable the toggle.
///
/// ## Usage:
/// ```dart
/// // Default inactive
/// BTToggle(label: 'Option', onChanged: (v) => setState(() => _p = v))
///
/// // Controlled active
/// BTToggle(label: 'Bold', pressed: true, onChanged: (v) => setState(() => _p = v))
///
/// // Outline with left icon
/// BTToggle(
///   label: 'Bold',
///   variant: BTToggleVariant.outline,
///   pressed: _isBold,
///   leftIcon: const Icon(Icons.format_bold, size: 16),
///   onChanged: (v) => setState(() => _isBold = v),
/// )
///
/// // Disabled
/// BTToggle(label: 'Option', onChanged: null)
/// ```
library;

import 'package:btech_tokens/btech_tokens.dart';
import 'package:btech_ui/src/components/atoms/toggle/toggle.types.dart';
import 'package:flutter/material.dart';

/// Pressable pill toggle atom. See file header for usage examples.
class BTToggle extends StatefulWidget {
  const BTToggle({
    required this.label,
    required this.onChanged,
    this.pressed = false,
    this.variant = BTToggleVariant.defaultVariant,
    this.size = BTToggleSize.md,
    this.leftIcon,
    this.rightIcon,
    super.key,
  });

  /// Text shown inside the toggle.
  final String label;

  /// Controlled pressed/active state. Default: false.
  final bool pressed;

  /// Visual style. Default: [BTToggleVariant.defaultVariant].
  final BTToggleVariant variant;

  /// Padding scale. Default: [BTToggleSize.md].
  final BTToggleSize size;

  /// Callback invoked on tap — receives the new pressed value.
  /// Pass `null` to disable the toggle.
  final ValueChanged<bool>? onChanged;

  /// Widget rendered to the left of [label] (16×16 recommended).
  final Widget? leftIcon;

  /// Widget rendered to the right of [label] (16×16 recommended).
  final Widget? rightIcon;

  bool get _disabled => onChanged == null;

  @override
  State<BTToggle> createState() => _BTToggleState();
}

class _BTToggleState extends State<BTToggle> {
  bool _isHovered = false;

  bool get _disabled => widget._disabled;

  // ── Color helpers ──────────────────────────────────────────────────────────

  Color _neutralSurface(BTColorTheme c, {required bool hover}) {
    final isDark = Theme.of(context).brightness == Brightness.dark;
    if (isDark) {
      return hover ? c.bg.subtler : c.bg.secondary;
    }
    return hover ? c.bg.subtler : c.bg.subtle;
  }

  Color _background(BTColorTheme c) {
    final active = widget.pressed;
    final hover = _isHovered && !_disabled;
    switch (widget.variant) {
      case BTToggleVariant.defaultVariant:
        if (active) return hover ? c.brand.primaryBold : c.brand.primary;
        return _neutralSurface(c, hover: hover);
      case BTToggleVariant.outline:
        if (active) return _neutralSurface(c, hover: hover);
        return hover ? _neutralSurface(c, hover: false) : Colors.transparent;
    }
  }

  Color _foreground(BTColorTheme c) {
    switch (widget.variant) {
      case BTToggleVariant.defaultVariant:
        return widget.pressed ? c.text.inverse : c.text.primary;
      case BTToggleVariant.outline:
        return c.text.secondary;
    }
  }

  /// Outline inactive (no hover) gets a 1 px border; all other states: no border.
  Border? _border(BTColorTheme c) {
    final showBorder = widget.variant == BTToggleVariant.outline &&
        !widget.pressed &&
        !(_isHovered && !_disabled);
    return showBorder ? Border.all(color: c.border.primary) : null;
  }

  // ── Build ──────────────────────────────────────────────────────────────────

  @override
  Widget build(BuildContext context) {
    final c = context.btColor;
    final radius = context.btRadius.sm;
    final isSmall = widget.size == BTToggleSize.sm;

    final padding = EdgeInsets.all(isSmall ? BTSpacing.xs : BTSpacing.sm);
    final fontSize = isSmall ? 12.0 : 14.0;
    final gap = BTSpacing.s2xs; // 2 px between icon and label

    final bg = _background(c);
    final fg = _foreground(c);
    final border = _border(c);

    final Widget content = Row(
      mainAxisSize: MainAxisSize.min,
      children: [
        if (widget.leftIcon != null) ...[
          IconTheme(
            data: IconThemeData(size: 16, color: fg),
            child: widget.leftIcon!,
          ),
          SizedBox(width: gap),
        ],
        Text(
          widget.label,
          style: TextStyle(
            color: fg,
            fontSize: fontSize,
            fontWeight: FontWeight.w500,
            fontFamily: BTTypography.fontFamily,
            height: 16 / fontSize,
            letterSpacing: 0,
          ),
        ),
        if (widget.rightIcon != null) ...[
          SizedBox(width: gap),
          IconTheme(
            data: IconThemeData(size: 16, color: fg),
            child: widget.rightIcon!,
          ),
        ],
      ],
    );

    Widget toggle = MouseRegion(
      cursor: _disabled ? SystemMouseCursors.forbidden : SystemMouseCursors.click,
      onEnter: _disabled ? null : (_) => setState(() => _isHovered = true),
      onExit: _disabled ? null : (_) => setState(() => _isHovered = false),
      child: GestureDetector(
        onTap: _disabled ? null : () => widget.onChanged!(!widget.pressed),
        onTapDown: _disabled ? null : (_) => setState(() {}),
        onTapCancel: _disabled ? null : () => setState(() {}),
        child: Semantics(
          button: true,
          toggled: widget.pressed,
          child: Container(
            decoration: BoxDecoration(
              color: bg,
              borderRadius: BorderRadius.circular(radius),
              border: border,
            ),
            child: Padding(padding: padding, child: content),
          ),
        ),
      ),
    );

    // Apply opacity when disabled — same bg/border visible at 50% opacity.
    if (_disabled) toggle = Opacity(opacity: 0.5, child: toggle);

    return toggle;
  }
}
